// ---------------------------------------------------------------------------
// NOTE SEARCH HELPER
// ---------------------------------------------------------------------------

/**
 * Search notes by keyword across title, content, and tags.
 */
export function searchNotes(notes, query) {
  if (!query || !query.trim()) return notes;
  const lower = query.toLowerCase();
  return notes.filter(note => {
    const title = (note.title || '').toLowerCase();
    const content = (note.content || note.text || '').toLowerCase();
    const category = (note.category || '').toLowerCase();
    const tags = (note.tags || []).join(' ').toLowerCase();
    return title.includes(lower) || content.includes(lower) || category.includes(lower) || tags.includes(lower);
  });
}

/**
 * Generate an auto-note from an event.
 */
export function generateAutoNote(eventType, context = {}) {
  const trigger = AUTO_NOTE_TRIGGERS.find(t => t.event === eventType);
  if (!trigger) return null;

  let text = trigger.template;
  for (const [key, value] of Object.entries(context)) {
    text = text.replace(`{${key}}`, value || 'unknown');
  }

  return {
    id: `note_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`,
    timestamp: Date.now(),
    category: eventType.startsWith('combat') ? 'combat' : eventType.startsWith('quest') ? 'quest' : 'misc',
    text,
    autoGenerated: true,
  };
}
